Every Rust backend developer writes code like this dozens of times: impl From<UserEntity> for UserResponse { fn from(e: UserEntity) -> Self { UserResponse { name: e.name, email: e.email, age: e.age, display_name: e.first_name, // renamed address: e.address.into(), // nested created_at: Default::default(), // not in source } }
} With struct-mapper, you replace all of that with a single derive macro: #[derive(MapFrom)]
#[map_from(UserEntity)]
struct UserResponse { name: String, email: String, age: u32, #[map(from = "first_name")] display_name: String, #[map(into)] address: AddressResponse, #[map(skip, default)] created_at: String,
}

